+@page "/board"
+@using sv_2f75ea8a445c494d8232517a9f2ea6b3.Components.Board
+@rendermode InteractiveServer
+@inject ITaskService TaskService
+
+<PageTitle>Kanban Board</PageTitle>
+
+<h3 class="mb-3">Kanban Board</h3>
+
+@if (isLoading)
+{
+    <div class="d-flex justify-content-center my-5">
+        <div class="spinner-border" role="status">
+            <span class="visually-hidden">Loading...</span>
+        </div>
+    </div>
+}
+else if (errorMessage is not null)
+{
+    <div class="alert alert-danger" role="alert">
+        <strong>Error:</strong> @errorMessage
+        <button class="btn btn-link" @onclick="LoadTasks">Retry</button>
+    </div>
+}
+else
+{
+    <BoardStats TotalCount="allTasks.Count"
+                TodoCount="todoTasks.Count"
+                InProgressCount="inProgressTasks.Count"
+                DoneCount="doneTasks.Count"
+                OverdueCount="allTasks.Count(t => t.DueDate < DateTime.Today)" />
+
+    <BoardSearchBar SearchText="@searchText" SearchTextChanged="HandleSearchChanged" />
+
+    <div class="row g-3">
+        <BoardColumn ColumnName="To Do"
+                     Status="To Do"
+                     Tasks="filteredTodo"
+                     CanMoveLeft="false"
+                     CanMoveRight="true"
+                     RightStatus="In Progress"
+                     OnTaskMoved="HandleTaskMoved"
+                     OnTaskCreated="HandleTaskCreated" />
+
+        <BoardColumn ColumnName="In Progress"
+                     Status="In Progress"
+                     Tasks="filteredInProgress"
+                     CanMoveLeft="true"
+                     CanMoveRight="true"
+                     LeftStatus="To Do"
+                     RightStatus="Done"
+                     OnTaskMoved="HandleTaskMoved"
+                     OnTaskCreated="HandleTaskCreated" />
+
+        <BoardColumn ColumnName="Done"
+                     Status="Done"
+                     Tasks="filteredDone"
+                     CanMoveLeft="true"
+                     CanMoveRight="false"
+                     LeftStatus="In Progress"
+                     OnTaskMoved="HandleTaskMoved"
+                     OnTaskCreated="HandleTaskCreated" />
+    </div>
+}
+
+@code {
+    private List<TaskItem> allTasks = new();
+    private string searchText = "";
+    private bool isLoading = true;
+    private string? errorMessage;
+
+    private List<TaskItem> todoTasks => allTasks.Where(t => t.Status == "To Do").ToList();
+    private List<TaskItem> inProgressTasks => allTasks.Where(t => t.Status == "In Progress").ToList();
+    private List<TaskItem> doneTasks => allTasks.Where(t => t.Status == "Done").ToList();
+
+    private List<TaskItem> filteredTodo => Filter(todoTasks);
+    private List<TaskItem> filteredInProgress => Filter(inProgressTasks);
+    private List<TaskItem> filteredDone => Filter(doneTasks);
+
+    private List<TaskItem> Filter(List<TaskItem> tasks)
+    {
+        if (string.IsNullOrWhiteSpace(searchText))
+            return tasks;
+        return tasks.Where(t => t.Title.Contains(searchText, StringComparison.OrdinalIgnoreCase)).ToList();
+    }
+
+    protected override async Task OnInitializedAsync()
+    {
+        await LoadTasks();
+    }
+
+    private async Task LoadTasks()
+    {
+        try
+        {
+            isLoading = true;
+            errorMessage = null;
+            allTasks = await TaskService.GetAllTasksAsync();
+        }
+        catch (Exception ex)
+        {
+            errorMessage = ex.Message;
+        }
+        finally
+        {
+            isLoading = false;
+        }
+    }
+
+    private void HandleSearchChanged(string value)
+    {
+        searchText = value;
+    }
+
+    private async Task HandleTaskMoved((int TaskId, string NewStatus) move)
+    {
+        try
+        {
+            await TaskService.UpdateTaskStatusAsync(move.TaskId, move.NewStatus);
+            var task = allTasks.First(t => t.Id == move.TaskId);
+            var index = allTasks.IndexOf(task);
+            allTasks[index] = task with { Status = move.NewStatus };
+        }
+        catch (Exception ex)
+        {
+            errorMessage = ex.Message;
+        }
+    }
+
+    private async Task HandleTaskCreated(AddTaskForm.NewTaskRequest request)
+    {
+        try
+        {
+            var newTask = await TaskService.CreateTaskAsync(request.Title, request.Assignee, request.Priority, request.DueDate);
+            allTasks.Add(newTask with { Status = request.Status });
+        }
+        catch (Exception ex)
+        {
+            errorMessage = ex.Message;
+        }
+    }
+}
+

